index 973943790c0a..30ec08236b59 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8280,7 +8280,16 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   // case, invert the predicate to make it so.
   CmpInst::Predicate LPred =
       LHSIsTrue ? LHS->getPredicate() : LHS->getInversePredicate();
-
+  // (add A, B) u< A <=> (add A, B) u< B
+  // If L0 is an add of L1 and R1, then LHS and RHS are equivalent.
+  if (L0 == R0 && match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))) &&
+      (LPred == ICmpInst::ICMP_ULT || LPred == ICmpInst::ICMP_UGE ||
+       LPred == ICmpInst::ICMP_UGT || LPred == ICmpInst::ICMP_ULE)) {
+    if (LPred == RPred)
+      return true;
+    if (LPred == ICmpInst::getInversePredicate(RPred))
+      return false;
+  }
   // Can we infer anything when the two compares have matching operands?
   bool AreSwappedOps;
   if (areMatchingOperands(L0, L1, R0, R1, AreSwappedOps))
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..e72f4ab24bbd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3250,10 +3250,30 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
         return Builder.CreateIsNotNeg(NewXor);
       }
     }
+  // Match (icmp ult (add A, B), A) | (icmp ult (add A, B), B)
+  // -> (icmp ult (add A, B), A)
+  // This is an unsigned add overflow check where both conditions are equivalent.
+  // For unsigned addition, overflow occurs iff sum < operand, and checking
+  // against either operand is sufficient.
+  if (!IsAnd && PredL == ICmpInst::ICMP_ULT && PredR == ICmpInst::ICMP_ULT) {
+    Value *A, *B;
+    // Check LHS: (icmp ult (add A, B), A)
+    if (match(LHS0, m_Add(m_Value(A), m_Value(B))) && LHS1 == A) {
+      // Check RHS: (icmp ult (add A, B), B)
+      if (RHS0 == LHS0 && RHS1 == B)
+        return LHS;
+    }
+    // Check LHS: (icmp ult (add B, A), A) - commuted add
+    if (match(LHS0, m_Add(m_Value(B), m_Value(A))) && LHS1 == A) {
+      // Check RHS: (icmp ult (add B, A), B)
+      if (RHS0 == LHS0 && RHS1 == B)
+        return LHS;
+    }
   }

   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }
+}

